/**
 * This file only contains an early prototype of the Tool Descriptor
 * concept.
 *
 * The goal would be to unify the typings as well as the logic as much
 * as possible with NodeDescriptors and their concept. For the prototype
 * the idea was to be as independent as possible.
 */
export interface IToolDescriptor {
    /**
     * Technical type or identifier of the Tool Descriptor.
     *
     * Any tool based on this descriptor will also have this set as its "type".
     * Example: "httpRequestV1" or "createZendeskTicketV1".
     */
    type: string;
    /**
     * Human-readable default label any Tool will get based on this descriptor.
     *
     * Once a tool was created base on the tool descriptor, it will have this as
     * its default label, but the label can be changed.
     * Example: "HTTP Request" or "Create Zendesk Ticket".
     */
    defaultLabel: string;
    /**
     * Human-readable default description any Tool will get based on this descriptor.
     *
     * Once a tool was created base on the tool descriptor, it will have this as
     * its default description, but the description can be changed.
     * Example: "Sends an HTTP request to a specified URL and returns the response."
     */
    defaultDescription: string;
    /**
     * List of default parameters any Tool will get based on this descriptor.
     *
     * Once a tool was created based on the tool descriptor, it will have these
     * as its initial parameters, but the customer can add additional parameters
     * to a particular instance of a tool.
     *
     * Example: An HTTP Request tool descriptor could have default parameters for
     * "method", "url", "headers" and "payload".
     */
    defaultParameters: IDefaultToolParameter[];
    /**
     * The fulfillment logic of a Tool can either be a "function" or a "chartReference"
     * pointing to a flow-like structure.
     *
     * Todo: Talk to Koenraad on how we can unify this - to be either a function or
     * a chart-reference. This is not part of this prototype right now.
     */
    function: TToolFunction;
}
declare const toolParameterTypes: readonly ["text", "select", "connection", "json", "keyValuePair"];
type TDefaultParameterType = typeof toolParameterTypes[number];
interface IDefaultToolParameter {
    key: string;
    label: string;
    type: TDefaultParameterType;
    description: string;
    defaultValue: any;
    params?: object;
}
export type TToolFunction = (params: IToolFunctionParams) => Promise<IToolFunctionReturnValue>;
export interface IToolFunctionParams {
    /**
     * The actual parameters of the tool. These are the default parameters
     * as well as additional parameters the customers added.
     */
    parameters: {
        [key: string]: any;
    };
}
/**
 * Tools need to return a key-value object. This data will be JSON serialized
 * and given to the LLM as a response. Because the object needs to be JSON serializable,
 * keys can't point to e.g. functions.
 */
export interface IToolFunctionReturnValue {
    [key: string]: any;
}
export declare const createToolDescriptor: (params: Partial<IToolDescriptor>) => IToolDescriptor;
export {};
